function testCreateUser\(token\) {
  const userData = JSON.stringify\({
    name: 'API Test User',
    email: 'apitest_' + Date.now\(\) + '@test.com',
    password: 'test123456',
    role: 'performance_marketer',
    specialization: 'API Testing',
    availability: 'available'
  }\);

  const req = http.request\({
    hostname: 'localhost',
    port: 5000,
    path: '/api/auth/create-user',
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': 'Bearer ' + token,
      'Content-Length': Buffer.byteLength\(userData\)
    }
  }, \(res\) => {
    let data = '';
    res.on\('data', chunk => data += chunk\);
    res.on\('end', \(\) => {
      console.log\('\\\\nCreate user response status:', res.statusCode\);
      console.log\('Create user response:', data\);

      try {
        const parsed = JSON.parse\(data\);
        if \(parsed.success\) {
          console.log\('\\\\n✅ User created via API!'\);
          console.log\('User data:', JSON.stringify\(parsed.data, null, 2\)\);
        } else {
          console.log\('\\\\n❌ User creation failed'\);
          console.log\('Error:', parsed.message || parsed.errors\);
        }
      } catch \(e\) {
        console.log\('Error parsing response:', e.message\);
      }
    }\);
  }\);

  req.on\('error', \(e\) => {
    console.log\('Create user error:', e.message\);
  }\);

  req.write\(userData\);
  req.end\(\);
}
